'use strict';(function(){var SESSION_KEY='ptt_chat_session';var _sessionId=localStorage.getItem(SESSION_KEY)||null;var _convId=null;var _maxMsgId=0;var _mode='ai';var _pollTimer=null;var _sending=false;var _started=false;function buildWidget(){var fab=document.createElement('div');fab.className='cw-fab';fab.innerHTML='<button class="cw-fab-btn" id="cw-fab-btn" aria-label="Mở chat tư vấn" aria-haspopup="dialog" aria-expanded="false">'+'<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2" aria-hidden="true"><path stroke-linecap="round" stroke-linejoin="round" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"/></svg>'+'<span class="cw-fab-unread" id="cw-fab-unread" hidden></span>'+'</button>';document.body.appendChild(fab);var panel=document.createElement('div');panel.id='cw-panel';panel.className='cw-panel';panel.setAttribute('role','dialog');panel.setAttribute('aria-modal','true');panel.setAttribute('aria-label','Chat tư vấn');panel.setAttribute('aria-hidden','true');panel.innerHTML='<div class="cw-head">'+'<div class="cw-head-avatar" aria-hidden="true">💬</div>'+'<div class="cw-head-info">'+'<p class="cw-head-name">PTT Support</p>'+'<p class="cw-head-status" id="cw-status-text">Sẵn sàng hỗ trợ</p>'+'</div>'+'<button class="cw-head-close" id="cw-close-btn" aria-label="Đóng chat">'+'<svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5" aria-hidden="true"><path stroke-linecap="round" d="M6 18L18 6M6 6l12 12"/></svg>'+'</button>'+'</div>'+'<div class="cw-messages" id="cw-messages" role="log" aria-live="polite" aria-label="Hội thoại"></div>'+'<div class="cw-input-area">'+'<textarea class="cw-input" id="cw-input" placeholder="Nhập câu hỏi…" rows="1" maxlength="2000" aria-label="Nhập tin nhắn"></textarea>'+'<button class="cw-send-btn" id="cw-send-btn" aria-label="Gửi">'+'<svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2" aria-hidden="true"><path stroke-linecap="round" stroke-linejoin="round" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"/></svg>'+'</button>'+'</div>';document.body.appendChild(panel);}
function openPanel(){var panel=document.getElementById('cw-panel');var fabBtn=document.getElementById('cw-fab-btn');if(!panel)return;panel.classList.add('is-open');panel.setAttribute('aria-hidden','false');if(fabBtn){fabBtn.classList.add('is-open');fabBtn.setAttribute('aria-expanded','true');}
clearUnread();if(!_started)startSession();var input=document.getElementById('cw-input');if(input)setTimeout(function(){input.focus();},80);}
function closePanel(){var panel=document.getElementById('cw-panel');var fabBtn=document.getElementById('cw-fab-btn');if(!panel)return;panel.classList.remove('is-open');panel.setAttribute('aria-hidden','true');if(fabBtn){fabBtn.classList.remove('is-open');fabBtn.setAttribute('aria-expanded','false');}
clearInterval(_pollTimer);_pollTimer=null;}
function isPanelOpen(){var panel=document.getElementById('cw-panel');return panel&&panel.classList.contains('is-open');}
function clearUnread(){var badge=document.getElementById('cw-fab-unread');if(badge){badge.textContent='';badge.hidden=true;}}
function showUnread(n){var badge=document.getElementById('cw-fab-unread');if(badge&&n>0){badge.textContent=n;badge.hidden=false;}}
function startSession(){_started=true;if(!_sessionId){_sessionId=generateId();localStorage.setItem(SESSION_KEY,_sessionId);}
setStatus('Đang kết nối…');fetch('/api/chat/start',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({session_id:_sessionId,page:location.pathname}),}).then(function(r){return r.json();}).then(function(d){if(!d.ok){setStatus('Lỗi kết nối');return;}
_convId=d.conv_id;_mode=d.mode||'ai';setStatus(_mode==='ai'?'Trả lời tự động AI':'Nhân viên hỗ trợ');addMsg('bot',d.welcome||'Xin chào! Tôi có thể giúp gì cho bạn?');startPolling();}).catch(function(){setStatus('Không kết nối được');});}
function startPolling(){if(_pollTimer)return;_pollTimer=setInterval(pollReplies,5000);}
function pollReplies(){if(!_sessionId||!isPanelOpen())return;fetch('/api/chat/poll/'+_sessionId+'?since='+_maxMsgId).then(function(r){return r.json();}).then(function(d){if(!d.ok||!d.messages||!d.messages.length)return;d.messages.forEach(function(m){if(m.id>_maxMsgId)_maxMsgId=m.id;if(m.sender!=='visitor')addMsg(m.sender,m.content);});}).catch(function(){});}
function sendMessage(){var input=document.getElementById('cw-input');if(!input||_sending)return;var text=input.value.trim();if(!text||!_sessionId)return;_sending=true;addMsg('visitor',text);input.value='';autoResize(input);showTyping();setSendDisabled(true);fetch('/api/chat/send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({session_id:_sessionId,message:text}),}).then(function(r){return r.json();}).then(function(d){hideTyping();if(!d.ok){addMsg('bot','Có lỗi xảy ra. Vui lòng thử lại.');}
else if(d.reply){var sender=d.sender||'ai';addMsg(sender,d.reply);if(d.reply_id&&d.reply_id>_maxMsgId)_maxMsgId=d.reply_id;}else if(d.queued){addMsg('bot','Tin nhắn đã gửi. Nhân viên sẽ phản hồi bạn sớm nhất!');}
if(d.msg_id&&d.msg_id>_maxMsgId)_maxMsgId=d.msg_id;}).catch(function(){hideTyping();addMsg('bot','Mất kết nối. Vui lòng kiểm tra internet và thử lại.');}).finally(function(){_sending=false;setSendDisabled(false);});}
function addMsg(sender,content){var msgs=document.getElementById('cw-messages');if(!msgs)return;hideTyping();var div=document.createElement('div');div.className='cw-msg cw-msg--'+sender;var avatarHtml='<div class="cw-msg-avatar" aria-hidden="true">'+
(sender==='visitor'?'👤':(sender==='staff'?'💼':'🤖'))+'</div>';div.innerHTML=(sender!=='visitor'?avatarHtml:'')+'<div class="cw-msg-bubble">'+escH(content)+'</div>'+
(sender==='visitor'?avatarHtml:'');msgs.appendChild(div);msgs.scrollTop=msgs.scrollHeight;if(!isPanelOpen())showUnread(1);}
var _typingEl=null;function showTyping(){if(_typingEl)return;var msgs=document.getElementById('cw-messages');if(!msgs)return;_typingEl=document.createElement('div');_typingEl.className='cw-typing';_typingEl.innerHTML='<div class="cw-msg-avatar" aria-hidden="true">🤖</div>'+'<div class="cw-typing-dots"><span class="cw-typing-dot"></span><span class="cw-typing-dot"></span><span class="cw-typing-dot"></span></div>';msgs.appendChild(_typingEl);msgs.scrollTop=msgs.scrollHeight;}
function hideTyping(){if(_typingEl&&_typingEl.parentNode)_typingEl.parentNode.removeChild(_typingEl);_typingEl=null;}
function setStatus(text){var el=document.getElementById('cw-status-text');if(el)el.textContent=text;}
function setSendDisabled(v){var btn=document.getElementById('cw-send-btn');if(btn)btn.disabled=v;}
function autoResize(el){el.style.height='auto';el.style.height=Math.min(el.scrollHeight,100)+'px';}
function generateId(){return Math.random().toString(36).slice(2)+Date.now().toString(36);}
function escH(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function wireEvents(){var fabBtn=document.getElementById('cw-fab-btn');var closeBtn=document.getElementById('cw-close-btn');var sendBtn=document.getElementById('cw-send-btn');var input=document.getElementById('cw-input');if(fabBtn)fabBtn.addEventListener('click',function(){isPanelOpen()?closePanel():openPanel();});if(closeBtn)closeBtn.addEventListener('click',closePanel);if(input){input.addEventListener('keydown',function(e){if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendMessage();}});input.addEventListener('input',function(){autoResize(input);});}
if(sendBtn)sendBtn.addEventListener('click',sendMessage);document.addEventListener('keydown',function(e){if(e.key==='Escape'&&isPanelOpen())closePanel();});var svcPricingBtn=document.querySelector('[data-open-consult-popup]');if(svcPricingBtn){svcPricingBtn.addEventListener('click',function(){openPanel();});}}
buildWidget();wireEvents();}());